import { describe, it, beforeAll } from 'vitest';
import { performance } from 'perf_hooks';
import { createRequire } from 'node:module';
const require = createRequire(import.meta.url);
import * as fs from 'fs';
import { transpile } from './babelfish';
import {
  buildPolyglotFnInput,
  id,
  callArg,
  member,
  varDecl,
  ret,
  initPolyglotBettiWasm,
} from './polyglot-betti-bridge';

const ITERATIONS = 1000;

describe('Babelfish Performance Benchmarks', () => {
  let wasmLoaded = false;

  beforeAll(async () => {
    try {
      const pkgPath = './open-source/gnosis/gnosis-betti-wasm/pkg/gnosis_betti_wasm.js';
      const initStart = performance.now();
      await initPolyglotBettiWasm('file://' + pkgPath);
      const initEnd = performance.now();
      console.log(`[Babelfish Benchmark] WASM loaded in ${(initEnd - initStart).toFixed(2)}ms\n`);
      wasmLoaded = true;
    } catch (e) {
      console.log("Could not load WASM for bench: ", e);
    }
  });

  it('runs generative transpilation benchmark for all languages', () => {
    if (!wasmLoaded) return;
    
    const input = buildPolyglotFnInput(
      'python',
      'heavy_compute_pipeline',
      ['dataset', 'config'],
      [
        varDecl(['cleaned'], callArg(member(id('dataset'), 'filter'), [id('config')])),
        varDecl(['mapped'], callArg(id('apply_transform'), [id('cleaned')])),
        varDecl(['reduced'], callArg(id('aggregate'), [id('mapped')])),
        ret(id('reduced'))
      ]
    );

    const targets = [
      'python', 'go', 'rust', 'gnot',
      'c', 'cpp', 'csharp', 'elixir', 'fsharp', 'haskell',
      'java', 'javascript', 'kotlin', 'lean', 'lua', 'ocaml',
      'php', 'ruby', 'scala', 'swift', 'typescript', 'zig'
    ];

    let outputLog = `Running generative transpilation benchmark for ${ITERATIONS} iterations per target...\n\n`;
    
    for (const target of targets) {
      let totalTime = 0;
      
      // Warmup
      try { transpile(input, { targetLanguage: target }); } catch(e) {}
      
      for (let i = 0; i < ITERATIONS; i++) {
          const start = performance.now();
          try {
              transpile(input, { targetLanguage: target });
          } catch (e) {
              // unsupported targets bounce here gracefully
          }
          totalTime += (performance.now() - start);
      }
      
      outputLog += `  - Target: ${target.padEnd(12)} | Avg Time: ${(totalTime / ITERATIONS).toFixed(4)}ms per AST cycle\n`;
    }
    outputLog += '\n';
    fs.writeFileSync('benchmark_results.txt', outputLog);
  });
});
